// Доступ к имени рабочего процесса осуществляется через _workflow.name
const workflow_name = $workflow.name; 

// Ожидаем имя типа "DB_Initializer_Schema_HR" 

// Есть ли в имени суффикс
const parsing = workflow_name.split('_');

if (parsing.length < 2) {
  throw new Error("Не указана схема для пользователя в названии процесса.");
}

// Берем последний элемент массива (индекс длина минус 1)
const schema_name = parsing[parsing.length - 1];

return [{ json: { scheme_name: schema_name } }];

// Доступ к имени рабочего процесса осуществляется через _workflow.name
const workflow_name = $workflow.name;

// Ожидаем имя типа "DB_Initializer_Schema_HR"

// Есть ли в имени суффикс
const parsing = workflow_name.split('_');
if (parsing.length < 2) {
  throw new Error("Не указана схема для пользователя в названии процесса.");
}

const schema_name = parsing[1];

return [{ json: { scheme_name: schema_name } }];

// const main = $('Тестовые данные').first();
const main = $('Лид').first();
const body = main.json.body;
const headers = main.json.headers;
const creatives = $input.all()

// UTM-параметры из тела запроса
const campaign_id = body.utm_id;  // id кампании
const campaign_name = body.utm_campaign;  // название кампании
const source_name = body.utm_source;  // название источника (соцсети)
const phone = body.phone;  // Телефон

// Парсим referer для извлечения параметров контента
const referer = headers.referer || '';
const getParam = (url, key) => {
  const match = url.match(new RegExp(`[?&]${key}=([^&]*)`));
  return match ? decodeURIComponent(match[1]) : null;
};
let content_id = getParam(referer, 'ad_id');  // id креатива или объявления
let content_name = getParam(referer, 'utm_content');  // название объявления

// Полный JSON лида
const lead_json = main.json;

// Ищем совпадение по creativity_id
const match = creatives.find(item => item.json.creativity_id === content_id);

// Если найдено — перезаписываем переменные
if (match) {
  content_id = match.json.id;           // внутренний ID из БД
  content_name = match.json.content_name; // название креатива из БД
}

// Формируем объект для записи в БД
const record = {
  campaign_id,
  phone,
  campaign_name,
  content_id,
  content_name,
  source_name,
  lead_json
};

// Возвращаем в формате n8n для следующей ноды
return [{ json: record }];

// Функция для безопасной вставки текста в HTML
const esc = (str) => String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// 1. Получаем данные из нод
const leadInfo = $('Подготовка записи в БД').first().json;
const summary = $('Сводка').first().json.report; // Тут уже могут быть <b> или *

// 2. Извлекаем и СРАЗУ экранируем только "грязные" данные
const source = esc(leadInfo.source_name || 'не определен');
const phone = esc(leadInfo.phone || 'нет номера');
const content = esc(leadInfo.content_name || 'не указано');

// 3. Формируем заголовок (теги <b> пишем ПРЯМО, не экранируя их)
const leadHeader = `<b>Лид из ${source}</b>
<b>Телефон</b>: ${phone}
<b>Объявление</b>: ${content}`;

// 4. Обрабатываем сводку (если там остались звездочки, меняем их на <b>)
const cleanSummary = summary.replace(/\*(.*?)\*/g, '<b>$1</b>');

return {
  report: `${leadHeader}\n\n${cleanSummary}`
};

